-- Additive runtime hardening. All state-changing entry points below are SECURITY DEFINER,
-- scope-checked, and are the only authenticated execution paths for workflow mutations.
create or replace function public.workflow_member_in_scope(p_user uuid,p_tenant uuid,p_organization uuid,p_facility uuid) returns boolean language sql stable security definer set search_path=public as $$ select p_user is not null and exists(select 1 from public.memberships m where m.user_id=p_user and m.active and m.tenant_id=p_tenant and (m.organization_id is null or m.organization_id=p_organization) and (m.facility_id is null or m.facility_id=p_facility)); $$;

create or replace function public.workflow_write_event(p_instance public.workflow_instances,p_kind text,p_action text,p_metadata jsonb default '{}'::jsonb) returns void language plpgsql security definer set search_path=public as $$ begin perform set_config('app.workflow_event_controlled','on',true); insert into public.workflow_events(instance_id,tenant_id,organization_id,facility_id,kind,action,metadata,created_by) values(p_instance.id,p_instance.tenant_id,p_instance.organization_id,p_instance.facility_id,p_kind,p_action,coalesce(p_metadata,'{}'::jsonb),auth.uid()); end $$;

create or replace function public.prevent_direct_workflow_mutation() returns trigger language plpgsql security definer set search_path=public as $$ begin
 if tg_table_name='workflow_events' and current_setting('app.workflow_event_controlled',true)<>'on' then raise exception 'Workflow events require a controlled function'; end if;
 if tg_table_name='workflow_instances' and (new.state_key is distinct from old.state_key or new.assignee_id is distinct from old.assignee_id or new.locked is distinct from old.locked) and current_setting('app.workflow_controlled',true)<>'on' then raise exception 'Workflow instance mutation requires a controlled function'; end if;
 if tg_table_name='workflow_approvals' and (new.status is distinct from old.status or new.comment is distinct from old.comment) and current_setting('app.workflow_controlled',true)<>'on' then raise exception 'Workflow approval mutation requires a controlled function'; end if;
 if tg_table_name='workflow_tasks' and (new.status is distinct from old.status or new.assignee_id is distinct from old.assignee_id or new.verified_by is distinct from old.verified_by or new.completion_notes is distinct from old.completion_notes) and current_setting('app.workflow_controlled',true)<>'on' then raise exception 'Workflow task mutation requires a controlled function'; end if;
 return coalesce(new,old); end $$;
drop trigger if exists workflow_direct_events_guard on public.workflow_events; create trigger workflow_direct_events_guard before insert on public.workflow_events for each row execute function public.prevent_direct_workflow_mutation();
drop trigger if exists workflow_direct_instances_guard on public.workflow_instances; create trigger workflow_direct_instances_guard before update on public.workflow_instances for each row execute function public.prevent_direct_workflow_mutation();
drop trigger if exists workflow_direct_approvals_guard on public.workflow_approvals; create trigger workflow_direct_approvals_guard before update on public.workflow_approvals for each row execute function public.prevent_direct_workflow_mutation();
drop trigger if exists workflow_direct_tasks_guard on public.workflow_tasks; create trigger workflow_direct_tasks_guard before update on public.workflow_tasks for each row execute function public.prevent_direct_workflow_mutation();

create or replace function public.request_workflow_approval(p_instance_id uuid,p_mode text,p_approver_ids uuid[],p_distinct_from uuid default null) returns uuid[] language plpgsql security definer set search_path=public as $$ declare i public.workflow_instances%rowtype; ids uuid[]:=array[]::uuid[]; approver uuid; n integer:=0; begin select * into i from public.workflow_instances where id=p_instance_id for update; if not found or i.locked or not public.can_workflow('workflows.approve',i.tenant_id,i.organization_id,i.facility_id) or p_mode not in ('single','sequential','parallel','any_one','unanimous') or coalesce(array_length(p_approver_ids,1),0)=0 then raise exception 'Approval request denied'; end if; if p_mode='single' and array_length(p_approver_ids,1)<>1 then raise exception 'Single approval requires exactly one approver'; end if; if cardinality(array(select distinct x from unnest(p_approver_ids) x))<>cardinality(p_approver_ids) then raise exception 'Duplicate approver denied'; end if; foreach approver in array p_approver_ids loop if approver=auth.uid() and p_distinct_from=auth.uid() then raise exception 'Requester self-approval denied'; end if; if approver=p_distinct_from or not public.workflow_member_in_scope(approver,i.tenant_id,i.organization_id,i.facility_id) then raise exception 'Approval approver is out of scope'; end if; n:=n+1; insert into public.workflow_approvals(instance_id,tenant_id,organization_id,facility_id,sequence,mode,approver_id,distinct_from_id,created_by) values(i.id,i.tenant_id,i.organization_id,i.facility_id,n,p_mode,approver,p_distinct_from,auth.uid()) returning id into approver; ids:=array_append(ids,approver); end loop; perform public.workflow_write_event(i,'approval','approval.requested',jsonb_build_object('mode',p_mode,'count',cardinality(ids))); return ids; end $$;

create or replace function public.approve_workflow_request(p_approval_id uuid,p_comment text default null) returns boolean language plpgsql security definer set search_path=public as $$ declare a public.workflow_approvals%rowtype; i public.workflow_instances%rowtype; complete boolean; begin select * into a from public.workflow_approvals where id=p_approval_id for update; select * into i from public.workflow_instances where id=a.instance_id for update; if not found or i.locked or auth.uid() is null or a.approver_id<>auth.uid() or a.status<>'requested' or a.distinct_from_id=auth.uid() or not public.can_workflow('workflows.approve',i.tenant_id,i.organization_id,i.facility_id) or not public.workflow_member_in_scope(auth.uid(),i.tenant_id,i.organization_id,i.facility_id) then raise exception 'Approval denied'; end if; if a.mode='sequential' and exists(select 1 from public.workflow_approvals x where x.instance_id=a.instance_id and x.mode='sequential' and x.sequence<a.sequence and x.status<>'approved') then raise exception 'Sequential approval is not ready'; end if; perform set_config('app.workflow_controlled','on',true); update public.workflow_approvals set status='approved',comment=nullif(trim(p_comment),'') where id=a.id; complete:=case when a.mode in ('single','any_one') then true else not exists(select 1 from public.workflow_approvals x where x.instance_id=a.instance_id and x.mode=a.mode and x.status<>'approved') end; perform public.workflow_write_event(i,'approval',case when complete then 'approval.completed' else 'approval.approved' end,jsonb_build_object('approvalId',a.id,'mode',a.mode)); return complete; end $$;

create or replace function public.reject_workflow_request(p_approval_id uuid,p_comment text) returns void language plpgsql security definer set search_path=public as $$ declare a public.workflow_approvals%rowtype; i public.workflow_instances%rowtype; begin select * into a from public.workflow_approvals where id=p_approval_id for update; select * into i from public.workflow_instances where id=a.instance_id for update; if not found or a.approver_id<>auth.uid() or a.status<>'requested' or not public.can_workflow('workflows.reject',i.tenant_id,i.organization_id,i.facility_id) or coalesce(trim(p_comment),'')='' then raise exception 'Rejection denied'; end if; perform set_config('app.workflow_controlled','on',true); update public.workflow_approvals set status='rejected',comment=trim(p_comment) where id=a.id; perform public.workflow_write_event(i,'approval','approval.rejected',jsonb_build_object('approvalId',a.id)); end $$;
create or replace function public.request_workflow_changes(p_approval_id uuid,p_comment text) returns void language plpgsql security definer set search_path=public as $$ declare a public.workflow_approvals%rowtype; i public.workflow_instances%rowtype; begin select * into a from public.workflow_approvals where id=p_approval_id for update; select * into i from public.workflow_instances where id=a.instance_id for update; if not found or a.approver_id<>auth.uid() or a.status<>'requested' or not public.can_workflow('workflows.approve',i.tenant_id,i.organization_id,i.facility_id) or coalesce(trim(p_comment),'')='' then raise exception 'Changes request denied'; end if; perform set_config('app.workflow_controlled','on',true); update public.workflow_approvals set status='changes_requested',comment=trim(p_comment) where id=a.id; perform public.workflow_write_event(i,'approval','approval.changes_requested',jsonb_build_object('approvalId',a.id)); end $$;

create or replace function public.create_workflow_task(p_instance_id uuid,p_title_en text,p_assignee_id uuid default null) returns uuid language plpgsql security definer set search_path=public as $$ declare i public.workflow_instances%rowtype; id uuid; begin select * into i from public.workflow_instances where id=p_instance_id for update; if not found or i.locked or not public.can_workflow('workflows.manage_tasks',i.tenant_id,i.organization_id,i.facility_id) or coalesce(trim(p_title_en),'')='' or (p_assignee_id is not null and not public.workflow_member_in_scope(p_assignee_id,i.tenant_id,i.organization_id,i.facility_id)) then raise exception 'Task creation denied'; end if; insert into public.workflow_tasks(instance_id,tenant_id,organization_id,facility_id,title_en,assignee_id,status,created_by,updated_by) values(i.id,i.tenant_id,i.organization_id,i.facility_id,trim(p_title_en),p_assignee_id,case when p_assignee_id is null then 'open' else 'assigned' end,auth.uid(),auth.uid()) returning id into id; perform public.workflow_write_event(i,'task','task.created',jsonb_build_object('taskId',id)); return id; end $$;
create or replace function public.assign_workflow_task(p_task_id uuid,p_assignee_id uuid,p_reason text default null) returns void language plpgsql security definer set search_path=public as $$ declare t public.workflow_tasks%rowtype; i public.workflow_instances%rowtype; begin select * into t from public.workflow_tasks where id=p_task_id for update; select * into i from public.workflow_instances where id=t.instance_id for update; if not found or i.locked or not public.can_workflow(case when t.assignee_id is null then 'workflows.assign' else 'workflows.reassign' end,i.tenant_id,i.organization_id,i.facility_id) or not public.workflow_member_in_scope(p_assignee_id,i.tenant_id,i.organization_id,i.facility_id) or (t.assignee_id is not null and coalesce(trim(p_reason),'')='') then raise exception 'Task assignment denied'; end if; perform set_config('app.workflow_controlled','on',true); update public.workflow_tasks set assignee_id=p_assignee_id,status='assigned',updated_at=now(),updated_by=auth.uid() where id=t.id; perform public.workflow_write_event(i,'task','task.assigned',jsonb_build_object('taskId',t.id)); end $$;
create or replace function public.complete_workflow_task(p_task_id uuid,p_notes text) returns void language plpgsql security definer set search_path=public as $$ declare t public.workflow_tasks%rowtype; i public.workflow_instances%rowtype; begin select * into t from public.workflow_tasks where id=p_task_id for update; select * into i from public.workflow_instances where id=t.instance_id for update; if not found or i.locked or t.assignee_id<>auth.uid() or t.status not in ('assigned','in_progress','reopened') or coalesce(trim(p_notes),'')='' or not public.workflow_member_in_scope(auth.uid(),i.tenant_id,i.organization_id,i.facility_id) then raise exception 'Task completion denied'; end if; perform set_config('app.workflow_controlled','on',true); update public.workflow_tasks set status='pending_verification',completion_notes=trim(p_notes),updated_at=now(),updated_by=auth.uid() where id=t.id; perform public.workflow_write_event(i,'task','task.completed',jsonb_build_object('taskId',t.id)); end $$;
create or replace function public.verify_workflow_task(p_task_id uuid) returns void language plpgsql security definer set search_path=public as $$ declare t public.workflow_tasks%rowtype; i public.workflow_instances%rowtype; begin select * into t from public.workflow_tasks where id=p_task_id for update; select * into i from public.workflow_instances where id=t.instance_id for update; if not found or i.locked or t.status<>'pending_verification' or not public.can_workflow('workflows.verify_tasks',i.tenant_id,i.organization_id,i.facility_id) then raise exception 'Task verification denied'; end if; perform set_config('app.workflow_controlled','on',true); update public.workflow_tasks set status='completed',verified_by=auth.uid(),updated_at=now(),updated_by=auth.uid() where id=t.id; perform public.workflow_write_event(i,'task','task.verified',jsonb_build_object('taskId',t.id)); end $$;
create or replace function public.reopen_workflow_task(p_task_id uuid,p_reason text) returns void language plpgsql security definer set search_path=public as $$ declare t public.workflow_tasks%rowtype; i public.workflow_instances%rowtype; begin select * into t from public.workflow_tasks where id=p_task_id for update; select * into i from public.workflow_instances where id=t.instance_id for update; if not found or i.locked or t.status not in ('pending_verification','completed') or coalesce(trim(p_reason),'')='' or not public.can_workflow('workflows.manage_tasks',i.tenant_id,i.organization_id,i.facility_id) then raise exception 'Task reopen denied'; end if; perform set_config('app.workflow_controlled','on',true); update public.workflow_tasks set status='reopened',verified_by=null,updated_at=now(),updated_by=auth.uid() where id=t.id; perform public.workflow_write_event(i,'task','task.reopened',jsonb_build_object('taskId',t.id,'reason',trim(p_reason))); end $$;
create or replace function public.cancel_workflow_task(p_task_id uuid,p_reason text) returns void language plpgsql security definer set search_path=public as $$ declare t public.workflow_tasks%rowtype; i public.workflow_instances%rowtype; begin select * into t from public.workflow_tasks where id=p_task_id for update; select * into i from public.workflow_instances where id=t.instance_id for update; if not found or i.locked or t.status in ('completed','cancelled') or coalesce(trim(p_reason),'')='' or not public.can_workflow('workflows.manage_tasks',i.tenant_id,i.organization_id,i.facility_id) then raise exception 'Task cancellation denied'; end if; perform set_config('app.workflow_controlled','on',true); update public.workflow_tasks set status='cancelled',updated_at=now(),updated_by=auth.uid() where id=t.id; perform public.workflow_write_event(i,'task','task.cancelled',jsonb_build_object('taskId',t.id,'reason',trim(p_reason))); end $$;

create or replace function public.add_workflow_comment(p_instance_id uuid,p_body text,p_visibility text default 'team') returns uuid language plpgsql security definer set search_path=public as $$ declare i public.workflow_instances%rowtype; id uuid; begin select * into i from public.workflow_instances where id=p_instance_id for update; if not found or auth.uid() is null or not public.can_workflow('workflows.view',i.tenant_id,i.organization_id,i.facility_id) or coalesce(trim(p_body),'')='' or p_visibility not in ('team','confidential') or (p_visibility='confidential' and not public.can_workflow('workflows.view_confidential_comments',i.tenant_id,i.organization_id,i.facility_id)) then raise exception 'Workflow comment denied'; end if; insert into public.workflow_comments(instance_id,tenant_id,organization_id,facility_id,body,visibility,created_by) values(i.id,i.tenant_id,i.organization_id,i.facility_id,trim(p_body),p_visibility,auth.uid()) returning id into id; perform public.workflow_write_event(i,'comment','comment.added',jsonb_build_object('commentId',id,'visibility',p_visibility)); return id; end $$;
create or replace function public.escalate_workflow_instance(p_instance_id uuid,p_minimum_interval_minutes integer default 60) returns void language plpgsql security definer set search_path=public as $$ declare i public.workflow_instances%rowtype; begin select * into i from public.workflow_instances where id=p_instance_id for update; if not found or not public.can_workflow('workflows.manage_escalations',i.tenant_id,i.organization_id,i.facility_id) or i.due_at is null or i.due_at>now() or p_minimum_interval_minutes<5 or exists(select 1 from public.workflow_reminders r where r.instance_id=i.id and r.kind='escalation' and r.last_sent_at>now()-make_interval(mins=>p_minimum_interval_minutes)) then raise exception 'Workflow escalation denied'; end if; insert into public.workflow_reminders(instance_id,tenant_id,organization_id,facility_id,channel,kind,minimum_interval_minutes,last_sent_at,created_by) values(i.id,i.tenant_id,i.organization_id,i.facility_id,'in_app','escalation',p_minimum_interval_minutes,now(),auth.uid()); perform public.workflow_write_event(i,'escalation','instance.escalated',jsonb_build_object('delivery','placeholder')); end $$;

-- Transition facts are deliberately not accepted from the client. Until a module adapter is registered,
-- required record fields, attachment requirements, and conditions fail closed instead of trusting JSON input.
create or replace function public.workflow_condition_matches(p_instance public.workflow_instances,p_condition jsonb) returns boolean language plpgsql stable security definer set search_path=public as $$ declare f text:=p_condition->>'field'; op text:=p_condition->>'operator'; actual text; expected text:=p_condition->>'value'; begin if f not in ('state_key','locked','due_at','approval_status','task_status') or op not in ('equals','not_equals','date_overdue','approval_status','task_status') then raise exception 'Unsupported workflow condition'; end if; if f='state_key' then actual:=p_instance.state_key; elsif f='locked' then actual:=p_instance.locked::text; elsif f='due_at' then return op='date_overdue' and p_instance.due_at is not null and p_instance.due_at<now(); elsif f='approval_status' then actual:=case when exists(select 1 from public.workflow_events e where e.instance_id=p_instance.id and e.action='approval.completed') then 'approved' else 'pending' end; else actual:=coalesce((select status::text from public.workflow_tasks t where t.instance_id=p_instance.id order by t.updated_at desc limit 1),'none'); end if; return case when op in ('equals','approval_status','task_status') then actual=expected when op='not_equals' then actual<>expected else false end; end $$;
create or replace function public.transition_workflow_instance(p_instance_id uuid,p_to text,p_reason text default null,p_comment text default null) returns void language plpgsql security definer set search_path=public as $$ declare i public.workflow_instances%rowtype; v public.workflow_versions%rowtype; tr jsonb; begin select * into i from public.workflow_instances where id=p_instance_id for update; select * into v from public.workflow_versions where id=i.workflow_version_id and status='published'; select value into tr from jsonb_array_elements(v.definition->'transitions') where value->>'from'=i.state_key and value->>'to'=p_to; if not found or i.locked or tr is null or not public.can_workflow(coalesce(tr->>'requiredPermission','workflows.transition'),i.tenant_id,i.organization_id,i.facility_id) then raise exception 'Workflow transition denied'; end if; if jsonb_array_length(coalesce(tr->'allowedRoles','[]'::jsonb))>0 then raise exception 'Role-gated transition requires a trusted role adapter'; end if; if coalesce((tr->>'requiresReason')::boolean,false) and coalesce(trim(p_reason),'')='' then raise exception 'Transition reason required'; end if; if coalesce((tr->>'requiresComment')::boolean,false) and coalesce(trim(p_comment),'')='' then raise exception 'Transition comment required'; end if; if coalesce((tr->>'requiresAttachment')::boolean,false) or jsonb_array_length(coalesce(tr->'requiredFields','[]'::jsonb))>0 then raise exception 'Transition requires trusted record facts adapter'; end if; if exists(select 1 from jsonb_array_elements(coalesce(tr->'conditions','[]'::jsonb)) c where not public.workflow_condition_matches(i,c)) then raise exception 'Workflow condition failed'; end if; if coalesce((tr->>'requiresApproval')::boolean,false) and not exists(select 1 from public.workflow_events e where e.instance_id=i.id and e.action='approval.completed') then raise exception 'Transition approval required'; end if; if exists(select 1 from jsonb_array_elements(coalesce(tr->'actions','[]'::jsonb)) a where a->>'kind' not in ('lock','unlock','timeline','reminder','escalate','create_task','request_approval','set_due_date','assign_user')) then raise exception 'Unsupported workflow action'; end if; perform set_config('app.workflow_controlled','on',true); update public.workflow_instances set state_key=p_to,updated_at=now(),updated_by=auth.uid() where id=i.id; if exists(select 1 from jsonb_array_elements(coalesce(tr->'actions','[]'::jsonb)) a where a->>'kind'='lock') then update public.workflow_instances set locked=true where id=i.id; end if; if exists(select 1 from jsonb_array_elements(coalesce(tr->'actions','[]'::jsonb)) a where a->>'kind'='unlock') then update public.workflow_instances set locked=false where id=i.id; end if; perform public.workflow_write_event(i,'transition','instance.transition',jsonb_build_object('from',i.state_key,'to',p_to,'reason',nullif(trim(p_reason),''),'comment',nullif(trim(p_comment),''))); end $$;

revoke all on function public.workflow_member_in_scope(uuid,uuid,uuid,uuid),public.workflow_write_event(public.workflow_instances,text,text,jsonb),public.prevent_direct_workflow_mutation() from public,anon,authenticated;
revoke all on function public.request_workflow_approval(uuid,text,uuid,uuid),public.approve_workflow_request(uuid,text),public.transition_workflow_instance(uuid,text,text,text,jsonb) from authenticated;
revoke all on function public.request_workflow_approval(uuid,text,uuid[],uuid),public.approve_workflow_request(uuid,text),public.reject_workflow_request(uuid,text),public.request_workflow_changes(uuid,text),public.create_workflow_task(uuid,text,uuid),public.assign_workflow_task(uuid,uuid,text),public.complete_workflow_task(uuid,text),public.verify_workflow_task(uuid),public.reopen_workflow_task(uuid,text),public.cancel_workflow_task(uuid,text),public.add_workflow_comment(uuid,text,text),public.escalate_workflow_instance(uuid,integer),public.transition_workflow_instance(uuid,text,text,text) from public,anon;
grant execute on function public.request_workflow_approval(uuid,text,uuid[],uuid),public.approve_workflow_request(uuid,text),public.reject_workflow_request(uuid,text),public.request_workflow_changes(uuid,text),public.create_workflow_task(uuid,text,uuid),public.assign_workflow_task(uuid,uuid,text),public.complete_workflow_task(uuid,text),public.verify_workflow_task(uuid),public.reopen_workflow_task(uuid,text),public.cancel_workflow_task(uuid,text),public.add_workflow_comment(uuid,text,text),public.escalate_workflow_instance(uuid,integer),public.transition_workflow_instance(uuid,text,text,text) to authenticated;
